#nullable enable // autogenerated  

using MukioI18n;
using MVZ2.GameContent.Contraptions;
using MVZ2.GameContent.Enemies;
using MVZ2.GameContent.Talk;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Level;
using MVZ2.Vanilla.Properties;
using MVZ2Logic;
using MVZ2Logic.Entities;
using MVZ2Logic.HeldItems;
using MVZ2Logic.Level;
using PVZEngine;
using PVZEngine.Buffs;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using PVZEngine.Level;
using Tools;

namespace MVZ2.GameContent.Stages
{
    [AutoStageDefinition(VanillaStageNames.AmethystTutorial)]
    public class AmethystTutorialStage : StageDefinition
    {
        public AmethystTutorialStage(string nsp, string name) : base(nsp, name)
        {
        }

        public override void OnStart(LevelEngine level)
        {
            base.OnStart(level);
            SetTutorialTimer(level, new FrameTimer(30));

            // 种子槽：变形发射器、火焰发射器、紫晶塔  
            level.SetSeedSlotCount(6);
            level.FillSeedPacks(new NamespaceID[]
            {
                VanillaContraptionID.transfenser,
                VanillaContraptionID.FireDispenser,
                VanillaContraptionID.amethystPylon,
                VanillaContraptionID.obsidian,
                VanillaContraptionID.GlowingObsidian,
                VanillaContraptionID.lightningOrb,
            });

            level.SetStarshardActive(false);
            level.SetTriggerActive(true);   // 紫晶塔靠触发(Trigger)调档，必须开启  
            level.SetBlueprintsActive(true);
            level.SetPickaxeActive(false);
            level.SetEnergy(9990);          // 教程给足能量，专注于机制演示  

            StartState(level, STATE_PLACE_PYLON);
        }

        public override void OnUpdate(LevelEngine level)
        {
            base.OnUpdate(level);
            UpdateState(level);
            level.CheckGameOver();
        }

        private void StartTimer(LevelEngine level, int timeout)
        {
            var timer = GetTutorialTimer(level);
            timer?.ResetTime(timeout);
        }
        private void RunTimer(LevelEngine level)
        {
            var timer = GetTutorialTimer(level);
            if (timer.RunToExpiredAndNotNull())
            {
                OnTimerStop(level);
            }
        }

        // 进入某状态时的一次性初始化：显示指引文字 + 布置箭头/生成怪  
        private void StartState(LevelEngine level, int state)
        {
            SetTutorialState(level, state);
            var textKey = tutorialStrings[state];
            var context = string.Format(CONTEXT_STATE, state);
            level.ShowAdvice(context, textKey, 1000, -1);
            switch (state)
            {
                case STATE_PLACE_PYLON:
                    {
                        // 引导玩家先种下紫晶塔  
                        var pack = level.GetSeedPack(VanillaContraptionID.amethystPylon);
                        if (pack != null)
                        {
                            level.SetHintArrowPointToBlueprint(pack.GetIndex());
                            pack.FullRecharge();
                        }
                    }
                    break;

                case STATE_TRIGGER_GEAR:
                    {
                        // 引导玩家用触发(Trigger)调档，改变紫晶塔光等级  
                        level.HideHintArrow();
                        level.SetHintArrowPointToTrigger();
                    }
                    break;

                // 依次刷出五种怨灵，每种对应一个需要不同颜色光才能显形的关卡  
                case STATE_WRAITH_WARRIOR:
                    level.HideHintArrow();
                    level.SpawnEnemy(VanillaSpawnID.WraithWarrior, 2);
                    break;
                case STATE_WRAITH_ARCHER:
                    level.SpawnEnemy(VanillaSpawnID.WraithArcher, 2);
                    break;
                case STATE_WRAITH_BERSERKER:
                    level.SpawnEnemy(VanillaSpawnID.WraithBerserker, 2);
                    break;
                case STATE_WRAITH_VANGUARD:
                    level.SpawnEnemy(VanillaSpawnID.WraithVanguard, 2);
                    break;
                case STATE_WRAITH_HEADLESS:
                    level.SpawnEnemy(VanillaSpawnID.WraithDullhan, 2);
                    break;

                case STATE_FINAL:
                    level.HideHintArrow();
                    StartTimer(level, 150);
                    break;
            }
        }

        // 每帧判断是否满足推进到下一状态的条件  
        private void UpdateState(LevelEngine level)
        {
            var state = GetTutorialState(level);
            switch (state)
            {
                case STATE_PLACE_PYLON:
                    {
                        var heldEntityID = level.GetHeldSeedEntityID();
                        if (heldEntityID == VanillaContraptionID.amethystPylon)
                        {
                            level.HideHintArrow();
                        }
                        // 场上出现紫晶塔即进入调档教学  
                        if (level.EntityExists(VanillaContraptionID.amethystPylon))
                        {
                            StartState(level, STATE_TRIGGER_GEAR);
                        }
                    }
                    break;

                case STATE_TRIGGER_GEAR:
                    {
                        // 玩家拿起触发器视为学会调档，进入实战  
                        var heldType = level.GetHeldItemType();
                        if (heldType == LogicHeldTypes.trigger)
                        {
                            StartState(level, STATE_WRAITH_WARRIOR);
                        }
                    }
                    break;

                // 每种怨灵：清场即进入下一种  
                case STATE_WRAITH_WARRIOR:
                    if (level.GetEntities(EntityTypes.ENEMY).Length <= 0)
                        StartState(level, STATE_WRAITH_ARCHER);
                    break;
                case STATE_WRAITH_ARCHER:
                    if (level.GetEntities(EntityTypes.ENEMY).Length <= 0)
                        StartState(level, STATE_WRAITH_BERSERKER);
                    break;
                case STATE_WRAITH_BERSERKER:
                    if (level.GetEntities(EntityTypes.ENEMY).Length <= 0)
                        StartState(level, STATE_WRAITH_VANGUARD);
                    break;
                case STATE_WRAITH_VANGUARD:
                    if (level.GetEntities(EntityTypes.ENEMY).Length <= 0)
                        StartState(level, STATE_WRAITH_HEADLESS);
                    break;
                case STATE_WRAITH_HEADLESS:
                    if (level.GetEntities(EntityTypes.ENEMY).Length <= 0)
                        StartState(level, STATE_FINAL);
                    break;

                case STATE_FINAL:
                    RunTimer(level);
                    break;
            }
        }

        // 定时器到期后的处理（仅收尾用）  
        private void OnTimerStop(LevelEngine level)
        {
            var state = GetTutorialState(level);
            switch (state)
            {
                case STATE_FINAL:
                    if (level.IsCleared)   // 已经清过一次就不再重复  
                        break;
                    level.HideAdvice();
                    level.HideHintArrow();
                    level.ResetHeldItem();
                    level.SetUIAndInputDisabled(true);
                    level.Clear();
                    break;
            }
        }

        public static FrameTimer? GetTutorialTimer(LevelEngine level) => level.GetProperty<FrameTimer>(PROP_TUTORIAL_TIMER);
        public static void SetTutorialTimer(LevelEngine level, FrameTimer value) => level.SetProperty(PROP_TUTORIAL_TIMER, value);
        public static int GetTutorialState(LevelEngine level) => level.GetProperty<int>(PROP_STATE);
        public static void SetTutorialState(LevelEngine level, int value) => level.SetProperty(PROP_STATE, value);
        private static readonly NamespaceID ID = VanillaStageID.AmethystTutorial;

        public static readonly string[] tutorialStrings = new string[]
        {
            STRING_STATE_0,
            STRING_STATE_1,
            STRING_STATE_2,
            STRING_STATE_3,
            STRING_STATE_4,
            STRING_STATE_5,
            STRING_STATE_6,
            STRING_STATE_7,
        };
        public const int STATE_PLACE_PYLON = 0;
        public const int STATE_TRIGGER_GEAR = 1;
        public const int STATE_WRAITH_WARRIOR = 2;
        public const int STATE_WRAITH_ARCHER = 3;
        public const int STATE_WRAITH_BERSERKER = 4;
        public const int STATE_WRAITH_VANGUARD = 5;
        public const int STATE_WRAITH_HEADLESS = 6;
        public const int STATE_FINAL = 7;

        public const string CONTEXT_STATE_PREFIX = "advice.amethyst_tutorial.";
        public const string CONTEXT_STATE = CONTEXT_STATE_PREFIX + "{0}";

        [TranslateMsg("教程关指引", CONTEXT_STATE_PREFIX + "0")]
        public const string STRING_STATE_0 = "放置紫晶塔！它能瞬间吸收周边器械的光并输出不同频率的光。";

        [TranslateMsg("教程关指引", CONTEXT_STATE_PREFIX + "1")]
        public const string STRING_STATE_1 = "用触发器驱动紫晶塔来切换它输出的光颜色！也可以通过放置不同颜色的器械来调色！";

        [TranslateMsg("教程关指引", CONTEXT_STATE_PREFIX + "2")]
        public const string STRING_STATE_2 = "亡魂战士只能被<color=#FF0000>红</color>光或<color=#FFD700>黄</color>光照亮，调出对应颜色击败它！";

        [TranslateMsg("教程关指引", CONTEXT_STATE_PREFIX + "3")]
        public const string STRING_STATE_3 = "亡魂弓箭手只能被<color=#00FF00>绿</color>光或<color=#00FFFF>青</color>光照亮！";

        [TranslateMsg("教程关指引", CONTEXT_STATE_PREFIX + "4")]
        public const string STRING_STATE_4 = "亡魂狂战士只能被<color=orange>橙</color>光或<color=grey>白</color>光照亮！";

        [TranslateMsg("教程关指引", CONTEXT_STATE_PREFIX + "5")]
        public const string STRING_STATE_5 = "亡魂冲锋者只能被<color=blue>蓝</color>光照亮！";

        [TranslateMsg("教程关指引", CONTEXT_STATE_PREFIX + "6")]
        public const string STRING_STATE_6 = "亡魂无头只能被<color=#FF0000>红</color>光或<color=purple>紫</color>光照亮！";

        [TranslateMsg("教程关指引", CONTEXT_STATE_PREFIX + "7")]
        public const string STRING_STATE_7 = "你已经掌握了紫晶塔！现在就去挑战更高难度的关卡吧！";

        public static readonly VanillaLevelPropertyMeta<int> PROP_STATE = new VanillaLevelPropertyMeta<int>("state");
        public static readonly VanillaLevelPropertyMeta<FrameTimer> PROP_TUTORIAL_TIMER = new VanillaLevelPropertyMeta<FrameTimer>("tutorialTimer");
    }
}
